let CurrentCount = SecurityEvent | where TimeGenerated > ago(1h) | where EventID == 4625 | count;
let HistAvg = SecurityEvent | where TimeGenerated between (ago(7d) .. ago(1h)) | where EventID == 4625 | summarize C=count() by bin(TimeGenerated,1h) | summarize Avg=avg(C);
CurrentCount | join HistAvg on 1==1 | extend Ratio=Count/Avg
